Material.Shader:

/* This is a vertex program for ...
 */

varying float setScalar;

void main()
{
  /* Transform the normal. */
  vec3 lightDirection = vec3(1.0, 0.6, 0.2);
  vec3 normal = normalize(gl_NormalMatrix*gl_Normal);
  vec3 lightDirectionCam = normalize( vec3(gl_ModelViewMatrix * (lightDirection, 1.0)));
  setScalar = lightDirectionCam * normal; // range [-1 1]
  setScalar = (setScalar + 1.0) * 6.0; // range [0 12]

  gl_Position = ftransform();
}




/* This is a fragment program ...
 */
varying float setScalar;

uniform vec4 Color0;
uniform vec4 Color1;

void main()
{
	//setScalar = setScalar * 12.0;
	int parity = setScalar;

	if(parity == 0)
	{
		gl_FragColor = Color1;
	}
	else if( setScalar > 11.9)
	{
		gl_FragColor = Color0;
	}
	else 
	{
		if(mod(parity, 2) == 0)
			gl_FragColor = Color1;
		else
			gl_FragColor = Color0;
	}

}
